@spec masterMix_spec  src=tests/specs/masterMix_spec.lua  loc=26  sha=4a6c156  cases=1

# Intent
  masterMix exposes a render-only toolbar segment (peak/loudness meter + master
  fader). The meter visuals and fader drag are exercised manually in REAPER --
  the pure-Lua ImGui fake can't drive drawlist or InvisibleButton. This pins the
  one thing the coordinator depends on: a segment with id 'master' and a render fn.

# Helpers
  @fn fakeChrome()  @ 15

# Cases
  @case 'exposes a master toolbar segment with a render fn'  [pure]  @ 19-24

# Fields (r read / w write incl. constructor keys)
  @field w __index  @ 8
  @field w chrome  @ 21
  @field w colour  @ 15
  @field w ctx  @ 21
  @field r id  @ 22
  @field w name  @ 19
  @field r preload  @ 6
  @field r render  @ 23
  @field w run  @ 20
  @field r segment  @ 22,23
